import{_ as e,o,c,d}from"./app.aee3b152.js";const i="/assets/image.IFC8T1.ac4862a0.png",l="/assets/image-20221009170046118.667d4bf6.png",r="/assets/image-20221009170314775.f0f23b15.png",t="/assets/image-20221009170518054.56bf21fe.png",a="/assets/image-20221009171236619.b3e3afff.png",s="/assets/image-20221009172516961.5797bed2.png",n="/assets/image-20221009173359550.5d3f9275.png",_={},g=d('<h1 id="cuda\u5B66\u4E60\u7B14\u8BB0" tabindex="-1"><a class="header-anchor" href="#cuda\u5B66\u4E60\u7B14\u8BB0" aria-hidden="true">#</a> CUDA\u5B66\u4E60\u7B14\u8BB0</h1><h2 id="_0-\u76EE\u6807" tabindex="-1"><a class="header-anchor" href="#_0-\u76EE\u6807" aria-hidden="true">#</a> 0 \u76EE\u6807</h2><ul><li>\u5FEB\u901F\u638C\u63E1<code>CUDA</code>\u7F16\u7A0B\u7684\u5927\u81F4\u65B9\u5F0F</li><li>\u4E86\u89E3<code>CUDA</code>\u8F6F\u786C\u4EF6\u7EC4\u7EC7\u67B6\u6784\u4E0E\u5173\u7CFB</li><li>\u4E86\u89E3\u5982\u4F55\u67E5\u627E\u6587\u6863</li></ul><h2 id="_1-\u4ECB\u7ECD" tabindex="-1"><a class="header-anchor" href="#_1-\u4ECB\u7ECD" aria-hidden="true">#</a> 1 \u4ECB\u7ECD</h2><h3 id="_1-1-\u67B6\u6784" tabindex="-1"><a class="header-anchor" href="#_1-1-\u67B6\u6784" aria-hidden="true">#</a> 1.1 \u67B6\u6784</h3><ul><li><p><strong>CUDA (Compute Unified Device Architecture)</strong>\uFF1A\u7EDF\u4E00\u8BA1\u7B97\u8BBE\u5907\u67B6\u6784\uFF0C\u5728 GPU \u4E0A\u53D1\u5E03\u7684\u4E00\u4E2A\u65B0\u7684\u786C\u4EF6\u548C\u8F6F\u4EF6\u67B6\u6784,\u5B83\u4E0D\u9700\u8981\u6620\u5C04\u5230\u4E00\u4E2A\u56FE\u578B API \u4FBF\u53EF\u5728 GPU \u4E0A\u7BA1\u7406\u548C\u8FDB\u884C\u5E76\u884C\u6570\u636E\u8BA1\u7B97</p></li><li><p><strong>CPU\u3001GPU\u67B6\u6784\u5BF9\u6BD4</strong>\uFF1AGPU \u88AB\u8BBE\u8BA1\u7528\u4E8E\u9AD8\u5BC6\u5EA6\u548C\u5E76\u884C\u8BA1\u7B97,\u66F4\u786E\u5207\u5730\u8BF4\u662F\u7528\u4E8E\u56FE\u5F62\u6E32\u67D3\uFF0C\u56E0\u6B64\u66F4\u591A\u7684\u6676\u4F53\u7BA1\u88AB\u6295\u5165\u5230\u6570\u636E\u5904\u7406\u800C\u4E0D\u662F\u6570\u636E\u7F13\u5B58\u548C\u6D41\u91CF\u63A7\u5236<img src="'+i+'" alt="image.IFC8T1"></p></li><li><p><strong>CUDA\u8F6F\u4EF6\u5806\u6808</strong>\uFF1ACUDA \u8F6F\u4EF6\u5806\u6808\u7531\u51E0\u5C42\u7EC4\u6210:\u4E00\u4E2A\u786C\u4EF6\u9A71\u52A8\u7A0B\u5E8F,\u4E00\u4E2A\u5E94\u7528\u7A0B\u5E8F\u7F16\u7A0B\u63A5\u53E3(API)\u548C\u5B83\u7684Runtime, \u8FD8\u6709\u4E8C\u4E2A\u9AD8\u7EA7\u7684\u901A\u7528\u6570\u5B66\u5E93,CUFFT \u548CCUBLAS<img src="'+l+'" alt="image-20221009170046118"></p></li><li><p><strong>CUDA\u5185\u5B58\u64CD\u4F5C</strong>\uFF1ACUDA \u63D0\u4F9B\u4E00\u822C DRAM \u5185\u5B58\u5BFB\u5740\u65B9\u5F0F: \u201C \u53D1\u6563 \u201D \u548C \u201C \u805A\u96C6 \u201D \u5185\u5B58\u64CD\u4F5C\uFF0C\u5B83\u53EF\u4EE5\u5728 DRAM\u7684\u4EFB\u4F55\u533A\u57DF\u8FDB\u884C\u8BFB\u5199\u6570\u636E\u7684\u64CD\u4F5C<img src="'+r+'" alt="image-20221009170314775"></p></li><li><p>\u5141\u8BB8\u5E76\u884C\u6570\u636E\u7F13\u51B2\u6216\u8005\u5728 On-chip \u5185\u5B58\u5171\u4EAB\u4F7F\u6570\u636E\u66F4\u63A5\u8FD1ALU\uFF0C\u53EF\u4EE5\u8FDB\u884C\u5FEB\u901F\u7684\u5E38\u89C4\u8BFB\u5199\u5B58\u53D6,\u5728\u7EBF\u7A0B\u4E4B\u95F4\u5171\u4EAB\u6570\u636E\u3002\u5E94\u7528\u7A0B\u5E8F\u53EF\u4EE5\u6700\u5C0F\u5316\u6570\u636E\u5230 DRAM \u7684 overfetch \u548C round-trips ,\u4ECE\u800C\u51CF\u5C11\u5BF9 DRAM \u5185\u5B58\u5E26\u5BBD\u7684\u4F9D\u8D56<img src="'+t+'" alt="image-20221009170518054"></p></li></ul><h3 id="_1-2-\u7F16\u7A0B\u6A21\u578B" tabindex="-1"><a class="header-anchor" href="#_1-2-\u7F16\u7A0B\u6A21\u578B" aria-hidden="true">#</a> 1.2 \u7F16\u7A0B\u6A21\u578B</h3><ul><li><p><strong>Kernel</strong>\uFF1A\u4E00\u4E2A\u88AB\u6267\u884C\u8BB8\u591A\u6B21\u4E0D\u540C\u6570\u636E\u7684\u5E94\u7528\u7A0B\u5E8F\u90E8\u5206,\u53EF\u4EE5\u88AB\u5206\u79BB\u6210\u4E3A\u4E00\u4E2A\u6709\u5F88\u591A\u4E0D\u540C\u7EBF\u7A0B\u5728\u8BBE\u5907\u4E0A\u6267\u884C\u7684\u51FD\u6570\uFF0C\u6700\u7EC8\u88AB\u7F16\u8BD1\u6210\u8BBE\u5907\u7684\u6307\u4EE4\u96C6</p></li><li><p><strong>DMA</strong>\uFF1A\u4E3B\u673A\u548C\u8BBE\u5907\u4F7F\u7528\u5B83\u4EEC\u81EA\u5DF1\u7684 DRAM ,\u4E3B\u673A\u5185\u5B58\u548C\u8BBE\u5907\u5185\u5B58\u3002\u5E76\u53EF\u4EE5\u901A\u8FC7\u5229\u7528\u8BBE\u5907\u9AD8\u6027\u80FD\u76F4\u63A5\u5185\u5B58\u5B58\u53D6 (<code>DMA</code>)\u7684\u5F15\u64CE( <code>API </code>)\u4ECE\u4E00\u4E2A <code>DRAM</code> \u590D\u5236\u6570\u636E\u5230\u5176\u4ED6 <code>DRAM</code></p></li><li><p><strong>\u7EBF\u7A0B\u6279\u5904\u7406</strong>\uFF1A\u7EBF\u7A0B\u6279\u5904\u7406\u5C31\u662F\u6267\u884C\u4E00\u4E2A\u88AB\u7EC4\u7EC7\u6210\u8BB8\u591A\u7EBF\u7A0B\u5757\u7684 <code>Kernel</code>\uFF0C\u4E3B\u673A\u53D1\u9001\u4E00\u4E2A\u8FDE\u7EED\u7684 <code>kernel</code> \u8C03\u7528\u5230\u8BBE\u5907\u3002\u6BCF\u4E2A <code>kernel </code>\u4F5C\u4E3A\u4E00\u4E2A\u7531\u7EBF\u7A0B\u5757\u7EC4\u6210\u7684\u6279\u5904\u7406\u7EBF\u7A0B\u6765\u6267\u884C<img src="'+a+'" alt="image-20221009171236619"></p></li><li><p><strong>Block</strong>\uFF1A\u5305\u542B\u591A\u4E2A\u7EBF\u7A0B\uFF0C\u7EBF\u7A0B\u95F4\u5171\u4EAB\u6570\u636E\uFF0C\u53EF\u5728<code>Kernel</code>\u4E2D\u6307\u5B9A\u540C\u6B65\u70B9\uFF0C\u4E00\u4E2A\u5757\u91CC\u7684\u7EBF\u7A0B\u88AB\u6302\u8D77\u76F4\u5230\u5B83\u4EEC\u6240\u6709\u90FD\u5230\u8FBE\u540C\u6B65\u70B9\uFF0C\u6BCF\u4E2A\u7EBF\u7A0B\u62E5\u6709<code>Block</code>\u5185\u7684<code>Thread ID</code></p></li><li><p><strong>Grid</strong>\uFF1A\u6267\u884C\u540C\u4E00\u4E2A <code>Kernel</code> \u7684\u5757\u53EF\u4EE5\u5408\u6210\u4E3A\u4E00\u4E2A<code>Grid</code>\uFF0C\u540C\u4E00\u4E2A<code>Grid</code>\u4E2D\u7684\u4E0D\u540C<code>Block</code>\u4E2D\u7684\u7EBF\u7A0B\u4E0D\u80FD\u901A\u8BAF\u548C\u540C\u6B65\uFF0C\u6BCF\u4E2A<code>Block</code>\u6709\u5BF9\u5E94\u7684<code>Block ID</code></p></li></ul><h3 id="_1-3-\u5185\u5B58\u6A21\u578B" tabindex="-1"><a class="header-anchor" href="#_1-3-\u5185\u5B58\u6A21\u578B" aria-hidden="true">#</a> 1.3 \u5185\u5B58\u6A21\u578B</h3><ul><li><p>\u7EBF\u7A0B\u5141\u8BB8\u8BBF\u95EE\u7684\u5185\u5B58\u7A7A\u95F4\uFF1A</p><ul><li><strong>\u8BFB\u5199</strong>\u6BCF\u6761\u7EBF\u7A0B\u7684<code>\u5BC4\u5B58\u5668</code></li><li><strong>\u8BFB\u5199</strong>\u6BCF\u6761\u7EBF\u7A0B\u7684<code>\u672C\u5730\u5185\u5B58</code></li><li><strong>\u8BFB\u5199</strong>\u6BCF\u4E2A<code>Block</code>\u7684<code>\u5171\u4EAB\u5185\u5B58</code></li><li><strong>\u8BFB\u5199</strong>\u6BCF\u4E2A<code>Grid</code>\u7684<code>\u5168\u5C40\u5185\u5B58</code></li><li><strong>\u53EA\u8BFB</strong>\u6BCF\u4E2A<code>Grid</code>\u7684<code>\u5E38\u91CF\u5185\u5B58</code></li><li><strong>\u53EA\u8BFB</strong>\u6BCF\u4E2A<code>Grid</code>\u7684<code>\u7EB9\u7406\u5185\u5B58</code></li></ul></li><li><p><img src="'+s+'" alt="image-20221009172516961"></p></li><li><p>\u5168\u5C40,\u5E38\u91CF,\u548C\u7EB9\u7406\u5185\u5B58\u7A7A\u95F4\u53EF\u4EE5\u901A\u8FC7\u4E3B\u673A\u6216\u8005\u540C\u4E00\u5E94\u7528\u7A0B\u5E8F\u6301\u7EED\u7684\u901A\u8FC7 kernel \u8C03\u7528\u6765\u5B8C\u6210\u8BFB\u53D6\u6216\u5199\u5165</p></li><li><p>\u5168\u5C40,\u5E38\u91CF,\u548C\u7EB9\u7406\u5185\u5B58\u7A7A\u95F4\u5BF9\u4E0D\u540C\u5185\u5B58\u7684\u7528\u6CD5\u52A0\u4EE5\u4F18\u5316\u3002\u7EB9\u7406\u5185\u5B58\u540C\u6837\u63D0\u4F9B\u4E0D\u540C\u7684\u5BFB\u5740\u6A21\u5F0F,\u4E5F\u4E3A\u4E00\u4E9B\u7279\u6B8A\u7684\u6570\u636E\u683C\u5F0F\u8FDB\u884C\u6570\u636E\u8FC7\u6EE4</p></li></ul><h3 id="_1-4-\u786C\u4EF6\u5B9E\u73B0" tabindex="-1"><a class="header-anchor" href="#_1-4-\u786C\u4EF6\u5B9E\u73B0" aria-hidden="true">#</a> 1.4 \u786C\u4EF6\u5B9E\u73B0</h3><ul><li><strong>SIMD</strong>\uFF1A\u5355\u6307\u4EE4\u591A\u6570\u636E\uFF0C\u5728\u7ED9\u5B9A\u65F6\u949F\u5468\u671F\u5185\uFF0C\u591A\u5904\u7406\u5668\u7684\u6BCF\u4E2A\u5904\u7406\u5668\u6267\u884C\u540C\u4E00\u6307\u4EE4\uFF0C\u64CD\u4F5C\u4E0D\u540C\u6570\u636E\uFF0C\u5E76\u884C\u6570\u636E\u7F13\u5B58\u6216\u5171\u4EAB\u5185\u5B58,\u88AB\u6240\u6709\u5904\u7406\u5668\u5171\u4EAB\u5B9E\u73B0\u5185\u5B58\u7A7A\u95F4\u5171\u4EAB\uFF0C\u4E00\u4E2A<code>Block</code>\u53EA\u88AB\u4E00\u4E2A\u591A\u5904\u7406\u5668\u5904\u7406<img src="'+n+'" alt="image-20221009173359550"></li><li><strong>Active</strong>\uFF1A\u88AB\u4E00\u4E2A\u591A\u5904\u7406\u5668\u6267\u884C\u7684<code>Block</code>,\u88AB\u79F0\u4F5C<code> active</code></li><li><strong>Warp</strong>\uFF1A\u6BCF\u4E2A<code>active</code>\u88AB\u5212\u5206\u4E3A\u591A\u4E2A<code>SIMD</code>\u65B9\u5F0F\u7684\u7EBF\u7A0B\u7EC4\uFF0C\u6BCF\u4E00\u7EC4\u79F0\u4E3A\u4E00\u4E2A<code>warp</code>\uFF0C\u6BCF\u4E2A<code>warp</code>\u5927\u5C0F\u76F8\u540C\uFF0C\u7EBF\u7A0B\u8C03\u5EA6\u7A0B\u5E8F\u5468\u671F\u6027\u5730\u4ECE\u4E00\u4E2A<code>warp</code>\u5207\u6362\u5230\u53E6\u4E00\u4E2A<code>warp</code></li></ul><h2 id="_2-api" tabindex="-1"><a class="header-anchor" href="#_2-api" aria-hidden="true">#</a> 2 API</h2><ul><li>C\u8BED\u8A00\u6269\u5C55\uFF1A <ul><li>\u51FD\u6570\u7C7B\u578B\u9650\u5B9A\uFF1A\u6307\u5B9A\u51FD\u6570\u6267\u884C\u7684\u4F4D\u7F6E\u548C\u8C03\u7528\u4F4D\u7F6E <ul><li><code>__device__</code> : \u8BBE\u5907\u4E0A\u6267\u884C\uFF0C\u4EC5\u53EF\u4ECE\u8BBE\u5907\u8C03\u7528</li><li><code>__global__</code>: \u8BBE\u5907\u4E0A\u6267\u884C\uFF0C\u4EC5\u53EF\u4ECE\u4E3B\u673A\u8C03\u7528</li><li><code>__host__</code>: \u4E3B\u673A\u4E0A\u6267\u884C\uFF0C\u4EC5\u53EF\u4ECE\u4E3B\u673A\u8C03\u7528</li></ul></li><li>\u53D8\u91CF\u7C7B\u578B\u9650\u5B9A\uFF1A\u6307\u5B9A\u8BBE\u5907\u4E0A\u53D8\u91CF\u7684\u5185\u5B58\u4F4D\u7F6E <ul><li><code>__device__</code>\uFF1A\u9A7B\u7559\u5728\u8BBE\u5907</li><li><code>__constant__</code>: \u9A7B\u7559\u5728\u5E38\u91CF\u5185\u5B58\u7A7A\u95F4</li><li><code>__shared__</code>: \u9A7B\u7559\u5728\u7EBF\u7A0B\u5757\u7684\u5171\u4EAB\u5185\u5B58\u7A7A\u95F4\u4E2D</li><li>\u53EA\u80FD\u901A\u8FC7\u8BBE\u5907\u4EE3\u7801\u4E2D\u7684<code>__device__</code>, <code>__shared__</code>\u6216<code>__constant__</code>\u53D8\u91CF\u6765\u83B7\u53D6\u5730\u5740\u3002<code>__device__</code>\u6216<code>__constant__</code>\u53D8\u91CF\u7684\u5730\u5740\u53EA\u80FD\u901A\u8FC7\u4E3B\u673A\u4EE3\u7801\u83B7\u5F97, <code>cudaGetSymbolAddress()</code></li></ul></li><li>\u5728\u8BBE\u5907\u4E0A\u6267\u884C\u7684\u65B9\u5F0F\u914D\u7F6E\u3001\u6307\u5B9A<code>Grid</code>\u548C<code>Block</code>\u7684\u7EF4\u6570\uFF0C<code>Block</code>\u548C<code>Thread</code>\u7684ID <ul><li>\u6240\u6709<code>__global__</code>\u51FD\u6570\u7684\u8C03\u7528\u5FC5\u987B\u6307\u5B9A\u6267\u884C\u914D\u7F6E\uFF0C\u6267\u884C\u914D\u7F6E\u5B9A\u4E49\u4E86\u901A\u5E38\u5728\u8BBE\u5907\u6267\u884C\u7684\u51FD\u6570\u7684<code>Grid</code>\u548C<code>Block</code>\u7684\u7EF4\u6570</li><li><strong>Dg</strong>: <code>dim3</code>\u7C7B\u578B\uFF0C\u6307\u5B9A<code>Grid</code>\u7EF4\u6570\uFF0C<code>Dg.x * Dg.y</code> \u7B49\u4E8E\u88AB\u53D1\u9001<code>Block</code>\u7684\u6570\u91CF</li><li><strong>Db</strong>: <code>dim3</code>\u7C7B\u578B\uFF0C\u6307\u5B9A<code>Block</code>\u7EF4\u6570\uFF0C<code>Db.x * Db.y * Db.z</code> \u7B49\u4E8E\u6BCF\u4E2A<code>Block</code>\u7684\u7EBF\u7A0B\u6570</li><li><strong>Ns</strong>: <code>size_t</code>\u7C7B\u578B\uFF0C\u6307\u5B9A\u5171\u4EAB\u5185\u5B58\u5927\u5C0F\uFF0C\u53EF\u88AB\u4EFB\u4F55\u5916\u90E8\u6570\u7EC4\u53D8\u91CF\u4F7F\u7528\uFF0C\u9ED8\u8BA4\u4E3A0\uFF0C\u53EF\u9009\u53C2\u6570</li><li><strong>S</strong>: <code>cudaStream_t</code>\u7C7B\u578B\uFF0C\u6307\u5B9A\u76F8\u5173<code>stream</code>\uFF0C\u9ED8\u8BA4\u4E3A0\uFF0C\u53EF\u9009\u53C2\u6570</li><li>\u793A\u4F8B\uFF1A <ul><li>\u58F0\u660E\uFF1A<code>__global__ void Func(float* parameter);</code></li><li>\u8C03\u7528\uFF1A<code>Func&lt;&lt;&lt; Dg, Db, Ns &gt;&gt;&gt;(parameter);</code></li></ul></li></ul></li></ul></li><li>\u5185\u7F6E\u53D8\u91CF\uFF1A <ul><li><strong>gridDim\uFF1A</strong> <code>dim3</code>\u7C7B\u578B\uFF0C\u6307\u5B9A<code>Grid</code>\u7EF4\u6570</li><li><strong>blockIdx\uFF1A</strong> <code>uint3</code>\u7C7B\u578B\uFF0C\u6307\u5B9A<code>Block ID</code></li><li><strong>blockDim\uFF1A</strong> <code>dim3</code>\u7C7B\u578B\uFF0C\u6307\u5B9A<code>Block</code>\u7EF4\u6570</li><li><strong>threadIdx\uFF1A</strong> <code>uint3</code>\u7C7B\u578B\uFF0C\u6307\u5B9A<code>Thread ID</code></li><li>\u5185\u7F6E\u53D8\u91CF\u4E0D\u5141\u8BB8\u53D6\u5F97\u4EFB\u4F55\u5730\u5740\u4E14\u4E0D\u5141\u8BB8\u8D4B\u503C\u5230\u4EFB\u4F55\u5185\u7F6E\u53D8\u91CF</li></ul></li><li>\u6BCF\u4E2A\u5305\u542BCUDA \u8BED\u8A00\u6269\u5C55\u7684\u6E90\u6587\u4EF6\u5FC5\u987B\u901A\u8FC7CUDA \u7F16\u8BD1\u5668<code>nvcc</code>\u7F16\u8BD1</li><li></li></ul>',14),h=[g];function p(u,m){return o(),c("div",null,h)}const A=e(_,[["render",p],["__file","cuda_blog.html.vue"]]);export{A as default};
